// Merge expanded compounds into main database
function mergeExpandedCompounds() {
    for (const [key, value] of Object.entries(CompoundsDBExpanded)) {
        if (!CompoundsDB[key]) {
            CompoundsDB[key] = value;
        }
    }
    // Rebuild search index
    CompoundSearchIndex.length = 0;
    Object.keys(CompoundsDB).forEach(key => {
        const c = CompoundsDB[key];
        CompoundSearchIndex.push({
            formula: key,
            type: 'compound',
            display: `${key} - ${c.nameEN}`,
            data: c
        });
    });
}

// Run merge on load
if (typeof CompoundsDB !== 'undefined') {
    mergeExpandedCompounds();
}
